import { useEffect, useRef, type RefObject } from 'react';
import {
  connectTooltip,
  tooltipManager,
  type TooltipPlacement,
  type TooltipConnector,
} from '@arvo/core';
import { useTooltipManager } from '../providers/TooltipContext';

export interface TooltipConfig {
  content: string;
  placement?: TooltipPlacement;
  shortcut?: string;
}

export type TooltipProp = string | TooltipConfig;

export interface UseTooltipOptions {
  triggerRef: RefObject<HTMLElement | null>;
  tooltip: TooltipProp | undefined;
  labelRef?: RefObject<HTMLElement | null>;
  autoOnTruncation?: boolean;
}

function resolveConfig(tooltip: TooltipProp): TooltipConfig {
  return typeof tooltip === 'string' ? { content: tooltip } : tooltip;
}

/**
 * Internal hook that wires a component's trigger element to the tooltip system.
 * Manages event listeners, content updates, and cleanup automatically.
 */
export function useTooltip(options: UseTooltipOptions): void {
  const { triggerRef, tooltip, labelRef, autoOnTruncation } = options;
  const ctxManager = useTooltipManager();
  const manager = ctxManager ?? tooltipManager;

  const connectorRef = useRef<TooltipConnector | null>(null);

  useEffect(() => {
    const anchor = triggerRef.current;
    if (!anchor || !tooltip) {
      connectorRef.current?.destroy();
      connectorRef.current = null;
      return;
    }

    const config = resolveConfig(tooltip);

    if (connectorRef.current) {
      connectorRef.current.update({
        anchor,
        content: config.content,
        placement: config.placement,
        shortcut: config.shortcut,
        labelElement: labelRef?.current ?? undefined,
        autoOnTruncation,
      });
    } else {
      connectorRef.current = connectTooltip(manager, {
        anchor,
        content: config.content,
        placement: config.placement,
        shortcut: config.shortcut,
        labelElement: labelRef?.current ?? undefined,
        autoOnTruncation,
      });
    }

    return () => {
      connectorRef.current?.destroy();
      connectorRef.current = null;
    };
  }, [triggerRef, tooltip, labelRef, autoOnTruncation, manager]);
}
